<?php

$path = __DIR__.'/../resources/views/comercio/dashboard.blade.php';
$content = file_get_contents($path);

if ($content === false) {
    fwrite(STDERR, "ERROR: No se pudo leer dashboard.blade.php\n");
    exit(1);
}

$buttonPattern = <<<'REGEX'
~<button\s+type="button"\s+class="commerce-admin__tab"\s+disabled>\s*Branding\s*</button>~s
REGEX;

$buttonReplacement = <<<'BLADE'
<button
                type="button"
                class="commerce-admin__tab {{ ($activeTab ?? 'usuarios') === 'branding' ? 'is-active' : '' }}"
                data-commerce-tab-button="branding"
                aria-pressed="{{ ($activeTab ?? 'usuarios') === 'branding' ? 'true' : 'false' }}"
            >
                Branding
            </button>
BLADE;

$content = preg_replace($buttonPattern, $buttonReplacement, $content, 1, $buttonCount);

if ($buttonCount !== 1) {
    fwrite(STDERR, "ERROR: No se encontro exactamente un boton Branding bloqueado.\n");
    exit(1);
}

$startMarker = '<div'."\n".'            class="commerce-tab-panel {{ ($activeTab ?? \'usuarios\') === \'branding\' ? \'is-active\' : \'\' }}"'."\n".'            data-commerce-tab-panel="branding"';
$start = strpos($content, $startMarker);

if ($start === false) {
    fwrite(STDERR, "ERROR: No se encontro el panel Branding actual.\n");
    exit(1);
}

$sectionEnd = strpos($content, "\n    </section>\n@endsection", $start);

if ($sectionEnd === false) {
    fwrite(STDERR, "ERROR: No se encontro el cierre del dashboard despues de Branding.\n");
    exit(1);
}

$panel = base64_decode('', true);

if ($panel === false) {
    fwrite(STDERR, "ERROR: No se pudo decodificar el panel Branding.\n");
    exit(1);
}

$content = substr($content, 0, $start)
    .$panel
    .substr($content, $sectionEnd);

if (file_put_contents($path, $content) === false) {
    fwrite(STDERR, "ERROR: No se pudo guardar dashboard.blade.php\n");
    exit(1);
}

echo "OK: Branding reemplazado con el diseño de referencia.\n";